4 | /**
5 |  * Fit-score bands — the ONLY place score thresholds live.
6 |  * Import getFitBand() wherever a band is needed; never re-implement.
7 |  * Color mapping follows docs/design-system.md §2.3: low fit is neutral
8 |  * "generic" gray, not red — red is reserved for real errors.
9 |  */
10 | export type FitBand = "generic" | "weak" | "mid" | "good" | "high";
11 | 
12 | export function getFitBand(score: number): FitBand {
13 |   if (score >= 85) return "high";
14 |   if (score >= 70) return "good";
15 |   if (score >= 55) return "mid";
16 |   if (score >= 40) return "weak";
17 |   return "generic";
18 | }
19 | 
20 | const BAND_FILL: Record<FitBand, string> = {
21 |   generic: "bg-fit-generic",
22 |   weak: "bg-fit-weak",
23 |   mid: "bg-fit-mid",
24 |   good: "bg-fit-good",
25 |   high: "bg-fit-high",
26 | };
27 | 
28 | /* weak/mid/good fail AA as text on parchment — fill-only (design-system.md §2.5). */
29 | const BAND_SCORE_TEXT: Record<FitBand, string> = {
30 |   generic: "text-muted-foreground",
31 |   weak: "text-foreground",
32 |   mid: "text-foreground",
33 |   good: "text-foreground",
34 |   high: "text-fit-high",
35 | };
36 | 
37 | type FitScoreBarProps = {
38 |   /** Integer 0–100 from GenerationOutput.fit_score. */
39 |   score: number;
40 |   /** Animate the fill on mount (the generate-reveal moment). */
41 |   animate?: boolean;
42 | } & ({ variant: "vanilla" } | { variant: "authorial"; authorName: string });
43 | 
44 | /**
45 |  * The hero metric of the app: a horizontal fill whose LENGTH carries the
46 |  * vanilla-vs-AutorIA contrast even in grayscale. Caption text ("34% generic"
47 |  * vs "87% Dickens-fit") makes the meaning explicit without color.
48 |  */
49 | export function FitScoreBar(props: FitScoreBarProps) {
50 |   const score = Math.max(0, Math.min(100, Math.round(props.score)));
51 |   const band = getFitBand(score);
52 |   const caption =
53 |     props.variant === "authorial"
54 |       ? en.studio.fitCaptionVoice(score, props.authorName)
55 |       : en.studio.fitCaptionGeneric(score);
56 | 
57 |   return (
58 |     <div className="flex flex-col gap-1.5">
59 |       <div className="flex items-baseline justify-between gap-3">
60 |         <span className="text-sm font-medium text-muted-foreground">
61 |           {caption}
62 |         </span>
63 |         <span
64 |           className={cn(
65 |             "font-mono text-2xl font-semibold tabular-nums leading-none",
66 |             BAND_SCORE_TEXT[band],
67 |           )}
68 |         >
69 |           {score}
70 |         </span>
71 |       </div>
72 |       <div
73 |         role="meter"
74 |         aria-valuemin={0}
75 |         aria-valuemax={100}
76 |         aria-valuenow={score}
77 |         aria-label={caption}
78 |         className="h-2 overflow-hidden rounded-full bg-fit-track"
79 |       >
80 |         <div
81 |           className={cn(
82 |             "h-full rounded-full",
83 |             BAND_FILL[band],
84 |             props.animate !== false && "animate-fit-grow",
85 |           )}
86 |           style={{ width: `${score}%` }}
87 |         />
88 |       </div>
89 |     </div>
90 |   );
91 | }
92 | 
93 | /** Empty-track placeholder shown while generation is pending or failed. */
94 | export function FitScoreBarPending() {
95 |   return (
96 |     <div className="flex flex-col gap-1.5" aria-hidden="true">
97 |       <div className="flex items-baseline justify-between gap-3">
98 |         <span className="text-sm font-medium text-muted-foreground">
99 |           {en.studio.fitPending}
100 |         </span>
101 |         <span className="font-mono text-2xl font-semibold tabular-nums leading-none text-muted-foreground">
102 |           —
103 |         </span>
104 |       </div>
105 |       <div className="h-2 rounded-full bg-fit-track" />
106 |     </div>
107 |   );
108 | }
