2 | 
3 | import { DistinctiveVocabHighlight } from "@/components/DistinctiveVocabHighlight";
4 | import { FitScoreBar, FitScoreBarPending } from "@/components/FitScoreBar";
5 | import { Button } from "@/components/ui/button";
