Contents of file frontend/src/lib/api.ts:

1 | /**
2 |  * Typed client for the AutorIA REST API (docs/api_contract.yaml).
3 |  * All response shapes mirror the contract via lib/types.ts — never invent fields here.
4 |  */
5 | import type { AuthorSummary, DocumentUploadAccepted } from "@/lib/types";
6 | 
7 | const API_BASE = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:8000";
8 | 
9 | async function parseOrThrow<T>(res: Response, label: string): Promise<T> {
10 |   if (!res.ok) {
11 |     throw new Error(`${label} failed with status ${res.status}`);
12 |   }
13 |   return res.json() as Promise<T>;
14 | }
15 | 
16 | /** GET /api/authors — preloaded authors plus any added via document upload. */
17 | export async function listAuthors(): Promise<AuthorSummary[]> {
18 |   const res = await fetch(`${API_BASE}/api/authors`, { cache: "no-store" });
19 |   return parseOrThrow<AuthorSummary[]>(res, "GET /api/authors");
20 | }
21 | 
22 | /**
23 |  * POST /api/authors/{author_id}/documents — multipart .txt/.md upload (202 async).
24 |  *
25 |  * CONTRACT GAP: the API has no create-author endpoint, yet listAuthors is
26 |  * documented as returning authors "added via document upload". The add-author
27 |  * flow therefore posts to a fresh slug and expects the backend to auto-create
28 |  * it; the contract's 404 for unknown author_id contradicts this. Flagged for
29 |  * the Sprint 1 contract pairing session.
30 |  */
31 | export async function uploadAuthorDocument(
32 |   authorId: string,
33 |   file: File,
34 |   title?: string,
35 | ): Promise<DocumentUploadAccepted> {
36 |   const form = new FormData();
37 |   form.append("file", file);
38 |   if (title) form.append("title", title);
39 |   const res = await fetch(
40 |     `${API_BASE}/api/authors/${encodeURIComponent(authorId)}/documents`,
41 |     { method: "POST", body: form },
42 |   );
43 |   return parseOrThrow<DocumentUploadAccepted>(
44 |     res,
45 |     "POST /api/authors/{id}/documents",
46 |   );
47 | }
48 | 
49 | /** Derives a URL-safe author slug from a display name (client-side id proposal). */
50 | export function slugifyAuthorName(name: string): string {
51 |   return name
52 |     .normalize("NFD")
53 |     .replace(/[\u0300-\u036f]/g, "")
54 |     .toLowerCase()
55 |     .replace(/[^a-z0-9]+/g, "-")
56 |     .replace(/^-+|-+$/g, "");
57 | }
