import { en } from "@/lib/i18n/en";

interface MetricChipProps {
  /** Numeric value to display (formatted as integer). */
  value: number;
  /** Label key within en.styleDna — "metricDocuments" | "metricTokens" | "metricSentences". */
  label: string;
